# Chat 타입 정의
type ChatRoom {
    id: ID!
    userId1: String!
    userId2: String!
    status: Int!
    createdAt: String!
    updatedAt: String!
    latestMessage: ChatMessage
    unreadCount: Int!
}

type ChatMessage {
    id: ID!
    chatRoomId: ID!
    senderId: String!
    content: String!
    messageType: Int!
    status: Int!
    attachments: [ChatMessageAttachment!]
    readAt: String
    createdAt: String!
}

type ChatMessageAttachment {
    id: ID!
    messageId: ID!
    fileUrl: String!
    fileType: Int!
    fileName: String!
    fileSize: Long!
    createdAt: String!
}

# Input 타입
input CreateChatRoomInput {
    userId2: String!
}

input SendMessageInput {
    chatRoomId: ID!
    content: String!
    messageType: Int!
    attachments: [AttachmentInput!]
}

input AttachmentInput {
    fileUrl: String!
    fileType: Int!
    fileName: String!
    fileSize: Long!
}

# Query/Mutation 확장
extend type Query {
    chatRoom(id: ID!): ChatRoom
    chatRooms(limit: Int, offset: Int): [ChatRoom!]!
    chatMessages(chatRoomId: ID!, limit: Int, offset: Int): [ChatMessage!]!
}

extend type Mutation {
    createChatRoom(input: CreateChatRoomInput!): ChatRoom!
    sendMessage(input: SendMessageInput!): ChatMessage!
    markMessageAsRead(messageId: ID!): ChatMessage!
    deleteMessage(messageId: ID!): Boolean!
    archiveChatRoom(chatRoomId: ID!): ChatRoom!
}
