#### Chat Service - 파일 업로드 처리:

```kotlin
// chat/src/main/kotlin/com/maum/backend/service/ChatService.kt
@Service
class ChatService(
    private val chatMessageRepository: ChatMessageRepository,
    private val attachmentRepository: ChatMessageAttachmentRepository,
    private val s3Service: S3Service,  // AWS S3 서비스
) {
    @Transactional
    fun sendMessageWithAttachments(
        chatRoomId: String,
        senderId: String,
        content: String,
        attachments: List<AttachmentInput>,
    ): ChatMessageEntity {
        // 메시지 저장
        val message = ChatMessageEntity(
            chatRoomId = chatRoomId,
            senderId = senderId,
            content = content,
            messageType = if (attachments.isNotEmpty()) 1 else 0, // 1: HasAttachment
        )
        val savedMessage = chatMessageRepository.save(message)

        // 첨부파일 저장
        attachments.forEach { attachment ->
            val attachmentEntity = ChatMessageAttachmentEntity(
                messageId = savedMessage.id,
                fileUrl = attachment.fileUrl,
                fileType = attachment.fileType,
                fileName = attachment.fileName,
                fileSize = attachment.fileSize,
            )
            attachmentRepository.save(attachmentEntity)
        }

        return savedMessage
    }
}
```

#### GraphQL Service - S3 업로드 URL 생성:

```kotlin
// graphql/src/main/kotlin/com/maum/backend/service/chat/FileUploadService.kt
@Service
class FileUploadService(
    private val s3Client: S3Client,  // AWS SDK
) {
    fun generatePresignedUrl(
        userId: String,
        fileName: String,
        fileSize: Long,
        contentType: String,
    ): String {
        val key = "chat/$userId/$fileName"
        // S3 presigned URL 생성 (15분 유효)
        return s3Client.generatePresignedUrl(
            bucket = "maum-files",
            key = key,
            duration = Duration.ofMinutes(15),
            httpMethod = HttpMethod.PUT,
        )
    }
}
